14	// limitations under the License.
15	//
16	
17	`include "defines.svh"
18	
19	import defines::*;
20	
21	//
22	// Drives control signals for single data rate (SDR) SDRAM, including
23	// auto refresh at appropriate intervals. An AXI bus interface initiates
24	// reads and writes.
25	// For performance, this lazily keeps rows open after accesses, tracking them
26	// independently for each bank and closing them only when necessary.
27	//
28	
29	module sdram_controller
30	    #(parameter DATA_WIDTH = 32,
31	    parameter ROW_ADDR_WIDTH = 12, // 4096 rows
32	    parameter COL_ADDR_WIDTH = 8, // 256 columns
33	
34	    // These are expressed in numbers of clocks. Each one is the number
35	    // of clocks of delay minus one. Compute this by dividing timing
36	    // specification for the part by the clock interval.
37	    parameter T_POWERUP = 10000,
38	    parameter T_ROW_PRECHARGE = 1,
39	    parameter T_AUTO_REFRESH_CYCLE = 3,
40	    parameter T_RAS_CAS_DELAY = 1,
41	    parameter T_REFRESH = 750,
42	    parameter T_CAS_LATENCY = 1)
43	
44	    (input                                  clk,
45	    input                                   reset,
46	
47	    // Interface to SDRAM
48	    output logic                            dram_clk,
49	    output logic                            dram_cke,
50	    output logic                            dram_cs_n,
51	    output logic                            dram_ras_n,
52	    output logic                            dram_cas_n,
53	    output logic                            dram_we_n,
54	    output logic[1:0]                       dram_ba,
55	    output logic[12:0]                      dram_addr,
56	    inout [DATA_WIDTH - 1:0]                dram_dq,
57	
58	    // Interface to bus
59	    axi4_interface.slave                    axi_bus,
60	
61	    // Performance counter events
62	    output logic                            perf_dram_page_miss,
63	    output logic                            perf_dram_page_hit);
64	
65	    localparam SDRAM_BURST_LENGTH = 8;
66	    localparam SDRAM_BURST_IDX_WIDTH = $clog2(SDRAM_BURST_LENGTH);
67	    localparam NUM_BANKS = 4;
68	    localparam MEMORY_SIZE = (1 << (ROW_ADDR_WIDTH + COL_ADDR_WIDTH)) * NUM_BANKS
69	        * (DATA_WIDTH / 8);
70	    localparam INTERNAL_ADDR_WIDTH = ROW_ADDR_WIDTH + COL_ADDR_WIDTH + $clog2(NUM_BANKS);
71	    localparam SDRAM_ADDR_WIDTH = $size(dram_addr);
72	
73	    typedef enum {
74	        STATE_INIT0,
75	        STATE_INIT1,
76	        STATE_INIT2,
77	        STATE_INIT3,
78	        STATE_IDLE,
79	        STATE_AUTO_REFRESH0,
80	        STATE_AUTO_REFRESH1,
81	        STATE_OPEN_ROW,
82	        STATE_READ_BURST,
83	        STATE_WRITE_BURST,
84	        STATE_CAS_WAIT,
85	        STATE_POWERUP,
86	        STATE_CLOSE_ROW
87	    } burst_state_t;
88	
89	    typedef enum logic[3:0] {
90	        CMD_MODE_REGISTER_SET = 4'b0000,
91	        CMD_AUTO_REFRESH      = 4'b0001,
92	        CMD_PRECHARGE         = 4'b0010,
93	        CMD_ACTIVATE          = 4'b0011,
94	        CMD_WRITE             = 4'b0100,
95	        CMD_READ              = 4'b0101,
96	        CMD_NOP               = 4'b1000
97	    } sdram_cmd_t;
98	
99	    localparam TIMER_WIDTH = 15;
100	
101	    // latched addresses and lengths are in terms of DATA_WIDTH transfers, not bytes.
102	    logic[TIMER_WIDTH - 1:0] refresh_timer_ff;
103	    logic[TIMER_WIDTH - 1:0] refresh_timer_nxt;
104	    logic[TIMER_WIDTH - 1:0] timer_ff;
105	    logic[TIMER_WIDTH - 1:0] timer_nxt;
106	    sdram_cmd_t command;
107	    burst_state_t state_ff;
108	    burst_state_t state_nxt;
109	    logic[SDRAM_BURST_IDX_WIDTH - 1:0] burst_offset_ff;
110	    logic[SDRAM_BURST_IDX_WIDTH - 1:0] burst_offset_nxt;
111	    logic[ROW_ADDR_WIDTH - 1:0] active_row[NUM_BANKS];
112	    logic bank_active[NUM_BANKS];
113	    logic output_enable;
114	    logic[DATA_WIDTH - 1:0] write_data;
115	    logic[INTERNAL_ADDR_WIDTH - 1:0] write_address;
116	    logic[7:0] write_length; // Like axi_bus.m_awlen, is num transfers - 1
117	    logic write_pending;
118	    logic[INTERNAL_ADDR_WIDTH - 1:0] read_address;
119	    logic[7:0] read_length;    // Like axi_bus.m_arlen, is num_transfers - 1
120	    logic read_pending;
121	    logic lfifo_empty;
122	    logic sfifo_full;
123	    logic[$clog2(NUM_BANKS) - 1:0] write_bank;
124	    logic[COL_ADDR_WIDTH - 1:0] write_column;
125	    logic[ROW_ADDR_WIDTH - 1:0] write_row;
126	    logic[$clog2(NUM_BANKS) - 1:0] read_bank;
127	    logic[COL_ADDR_WIDTH - 1:0] read_column;
128	    logic[ROW_ADDR_WIDTH - 1:0] read_row;
129	    logic lfifo_enqueue;
130	    logic access_is_read_ff;
131	    logic access_is_read_nxt;
132	
133	    assign axi_bus.s_arready = !read_pending;
134	    assign axi_bus.s_awready = !write_pending;
135	    assign axi_bus.s_rvalid = !lfifo_empty;
136	    assign axi_bus.s_wready = !sfifo_full;
137	    assign axi_bus.s_bvalid = !reset;    // Hack: pretend we always have a write result
138	
139	    // Each fifo can hold an entire SDRAM burst to avoid delays due
140	    // to the external bus.
141	
142	    sync_fifo #(.WIDTH(DATA_WIDTH), .SIZE(SDRAM_BURST_LENGTH)) load_fifo(
143	        .clk(clk),
144	        .reset(reset),
145	        .flush_en(1'b0),
146	        .full(),
147	        .almost_empty(),
148	        .almost_full(),
149	        .empty(lfifo_empty),
150	        .enqueue_value(dram_dq),
151	        .enqueue_en(lfifo_enqueue),
152	        .dequeue_en(axi_bus.m_rready && axi_bus.s_rvalid),
153	        .dequeue_value(axi_bus.s_rdata));
154	
155	    sync_fifo #(.WIDTH(DATA_WIDTH), .SIZE(SDRAM_BURST_LENGTH)) store_fifo(
156	        .clk(clk),
157	        .reset(reset),
158	        .flush_en(1'b0),
159	        .full(sfifo_full),
160	        .almost_empty(),
161	        .almost_full(),
162	        .dequeue_value(write_data),
163	        .dequeue_en(output_enable),
164	        .enqueue_value(axi_bus.m_wdata),
165	        .enqueue_en(axi_bus.s_wready && axi_bus.m_wvalid),
166	        .empty());
167	
168	    assign {dram_cs_n, dram_ras_n, dram_cas_n, dram_we_n} = command;
169	    assign dram_cke = 1;
170	    assign dram_clk = clk;
171	    assign {write_row, write_bank, write_column} = write_address;
172	    assign {read_row, read_bank, read_column} = read_address;
173	
174	    assign dram_dq = output_enable ? write_data : {DATA_WIDTH{1'hZ}};
175	
176	    initial
177	    begin
178	        // Currently a requirement because narrowing or expanding isn't implemented.
179	        assert(`AXI_DATA_WIDTH == DATA_WIDTH);
180	    end
181	
182	    // Next state logic. When there is a delay between states, timer_ff tracks
183	    // how many cycles are remaining. state_ff will point to the *next* state
184	    // during this interval, but the  control signals associated with the state
185	    // (in the case below) won't be asserted until the timer counts down to zero.
186	    always_comb
187	    begin
188	        // Default values
189	        output_enable = 0;
190	        command = CMD_NOP;
191	        timer_nxt = TIMER_WIDTH'(0);
192	        burst_offset_nxt = 0;
193	        state_nxt = state_ff;
194	        dram_ba = 0;
195	        dram_addr = 0;
196	        perf_dram_page_miss = 0;
197	        perf_dram_page_hit = 0;
198	        access_is_read_nxt = access_is_read_ff;
199	
200	        lfifo_enqueue = 0;
201	        if (refresh_timer_ff != 0)
202	            refresh_timer_nxt = refresh_timer_ff - TIMER_WIDTH'(1);
203	        else
204	            refresh_timer_nxt = TIMER_WIDTH'(0);
205	
206	        if (timer_ff != 0)
207	            timer_nxt = timer_ff - TIMER_WIDTH'(1); // Wait for timer to expire
208	        else
209	        begin
210	            // Progress to next state.
211	            unique case (state_ff)
212	                STATE_POWERUP:
213	                begin
214	                    timer_nxt = TIMER_WIDTH'(T_POWERUP);    // Wait for clock to be stable
215	                    state_nxt = STATE_INIT0;
216	                end
217	
218	                STATE_INIT0:
219	                begin
220	                    // Step 1: send precharge all command
221	                    dram_addr = {SDRAM_ADDR_WIDTH{1'b1}};
222	                    command = CMD_PRECHARGE;
223	                    timer_nxt = TIMER_WIDTH'(T_ROW_PRECHARGE);
224	                    state_nxt = STATE_INIT1;
225	                end
226	
227	                STATE_INIT1:
228	                begin
229	                    // Step 2: send two auto refresh commands
230	                    dram_addr = {SDRAM_ADDR_WIDTH{1'b1}};
231	                    command = CMD_AUTO_REFRESH;
232	                    timer_nxt = TIMER_WIDTH'(T_AUTO_REFRESH_CYCLE);
233	                    state_nxt = STATE_INIT2;
234	                end
235	
236	                STATE_INIT2:
237	                begin
238	                    dram_addr = {SDRAM_ADDR_WIDTH{1'b1}};
239	                    command = CMD_AUTO_REFRESH;
240	                    timer_nxt = TIMER_WIDTH'(T_AUTO_REFRESH_CYCLE);
241	                    state_nxt = STATE_INIT3;
242	                end
243	
244	                STATE_INIT3:
245	                begin
246	                    // Step 3: set the mode register
247	                    // CAS latency is hardcoded to 2 clocks
248	                    command = CMD_MODE_REGISTER_SET;
249	                    dram_addr = SDRAM_ADDR_WIDTH'('b000_0_00_010_0_011);
250	                    dram_ba = 2'b00;
251	                    state_nxt = STATE_IDLE;
252	                end
253	
254	                STATE_IDLE:
255	                begin
256	                    if (refresh_timer_ff == 0)
257	                    begin
258	                        // Need to perform an auto-refresh cycle.  If any rows are open,
259	                        // precharge all of them now.  Otherwise proceed directly to
260	                        // refresh.
261	                        if (bank_active[0] | bank_active[1] | bank_active[2] | bank_active[3])
262	                            state_nxt = STATE_AUTO_REFRESH0;
263	                        else
264	                            state_nxt = STATE_AUTO_REFRESH1;
265	                    end
266	                    else if (lfifo_empty && read_pending
267	                        && (!write_pending || write_address != read_address))
268	                    begin
269	                        // Start a read burst. Reads have priority to avoid starving
270	                        // the VGA controller, but we check above to ensure there isn't
271	                        // a write already pending for this address (otherwise we will
272	                        // get stale data).
273	                        access_is_read_nxt = 1;
274	                        if (!bank_active[read_bank])
275	                        begin
276	                            // Row is not open in this bank, need to pen it.
277	                            perf_dram_page_miss = 1;
278	                            state_nxt = STATE_OPEN_ROW;
279	                        end
280	                        else if (read_row != active_row[read_bank])
281	                        begin
282	                            // Different row is already open in this bank, close it first.
283	                            perf_dram_page_miss = 1;
284	                            state_nxt = STATE_CLOSE_ROW;
285	                        end
286	                        else
287	                        begin
288	                            perf_dram_page_hit = 1;
289	                            state_nxt = STATE_CAS_WAIT;
290	                        end
291	                    end
292	                    else if (write_pending && sfifo_full
293	                        && (!read_pending || write_address == read_address))
294	                    begin
295	                        // Start a write burst.
296	                        // Don't start the burst if a read is pending and the FIFO is full.
297	                        // This is a hack to avoid starving the VGA controller.  However, do
298	                        // start the write if the read is for data we are about to write
299	                        // (write_address == read_address above), which avoids a nasty race
300	                        // condition that corrrupts data.
301	                        access_is_read_nxt = 0;
302	                        if (!bank_active[write_bank])
303	                        begin
304	                            // Row is not open, do that
305	                            perf_dram_page_miss = 1;
306	                            state_nxt = STATE_OPEN_ROW;
307	                        end
308	                        else if (write_row != active_row[write_bank])
309	                        begin
310	                            // Different row open in this bank, close
311	                            perf_dram_page_miss = 1;
312	                            state_nxt = STATE_CLOSE_ROW;
313	                        end
314	                        else
315	                        begin
316	                            perf_dram_page_hit = 1;
317	                            state_nxt = STATE_WRITE_BURST;
318	                        end
319	                    end
320	                end
321	
322	                STATE_CLOSE_ROW:
323	                begin
324	                    // Precharge a single bank that has an open row in preparation
325	                    // for a transfer.
326	                    dram_addr =  {SDRAM_ADDR_WIDTH{1'b0}};
327	                    if (access_is_read_ff)
328	                        dram_ba = read_bank;
329	                    else
330	                        dram_ba = write_bank;
331	
332	                    command = CMD_PRECHARGE;
333	                    timer_nxt = TIMER_WIDTH'(T_ROW_PRECHARGE);
334	                    state_nxt = STATE_OPEN_ROW;
335	                end
336	
337	                STATE_OPEN_ROW:
338	                begin
339	                    if (access_is_read_ff)
340	                    begin
341	                        dram_ba = read_bank;
342	                        dram_addr = SDRAM_ADDR_WIDTH'(read_row);
343	                        state_nxt = STATE_CAS_WAIT;
344	                    end
345	                    else
346	                    begin
347	                        dram_ba = write_bank;
348	                        dram_addr = SDRAM_ADDR_WIDTH'(write_row);
349	                        state_nxt = STATE_WRITE_BURST;
350	                    end
351	                    command = CMD_ACTIVATE;
352	                    timer_nxt = TIMER_WIDTH'(T_RAS_CAS_DELAY);
353	                end
354	
355	                STATE_CAS_WAIT:
356	                begin
357	                    command = CMD_READ;
358	                    dram_addr = SDRAM_ADDR_WIDTH'(read_column);
359	                    dram_ba = read_bank;
360	                    timer_nxt = TIMER_WIDTH'(T_CAS_LATENCY);
361	                    state_nxt = STATE_READ_BURST;
362	                end
363	
364	                STATE_READ_BURST:
365	                begin
366	                    lfifo_enqueue = 1;
367	                    burst_offset_nxt = burst_offset_ff + SDRAM_BURST_IDX_WIDTH'(1);
368	                    if (burst_offset_ff == SDRAM_BURST_IDX_WIDTH'(SDRAM_BURST_LENGTH - 1))
369	                        state_nxt = STATE_IDLE;
370	                end
371	
372	                STATE_WRITE_BURST:
373	                begin
374	                    output_enable = 1;
375	                    if (burst_offset_ff == 0)
376	                    begin
377	                        // On first cycle
378	                        dram_ba = write_bank;
379	                        dram_addr = SDRAM_ADDR_WIDTH'(write_column);
380	                        command = CMD_WRITE;
381	                    end
382	
383	                    burst_offset_nxt = burst_offset_ff + SDRAM_BURST_IDX_WIDTH'(1);
384	                    if (burst_offset_ff == SDRAM_BURST_IDX_WIDTH'(SDRAM_BURST_LENGTH - 1))
385	                        state_nxt = STATE_IDLE;
386	                end
387	
388	                STATE_AUTO_REFRESH0:
389	                begin
390	                    // Precharge all banks before auto-refresh
391	                    dram_addr = SDRAM_ADDR_WIDTH'('b0010000000000);    // XXX parameterize
392	                    command = CMD_PRECHARGE;
393	                    timer_nxt = TIMER_WIDTH'(T_ROW_PRECHARGE);
394	                    state_nxt = STATE_AUTO_REFRESH1;
395	                end
396	
397	                STATE_AUTO_REFRESH1:
398	                begin
399	                    command = CMD_AUTO_REFRESH;
400	                    timer_nxt = TIMER_WIDTH'(T_AUTO_REFRESH_CYCLE);
401	                    refresh_timer_nxt = TIMER_WIDTH'(T_REFRESH);
402	                    state_nxt = STATE_IDLE;
403	                end
404	
405	                default:
406	                    state_nxt = STATE_IDLE;
407	            endcase
408	        end
409	    end
410	
411	    always_ff @(posedge clk, posedge reset)
412	    begin
413	        if (reset)
414	        begin : doreset
415	            for (int i = 0; i < NUM_BANKS; i++)
416	            begin
417	                active_row[i] <= 0;
418	                bank_active[i] <= 0;
419	            end
420	
421	            state_ff <= STATE_INIT0;
422	            refresh_timer_ff <= TIMER_WIDTH'(T_REFRESH);
423	
424	            access_is_read_ff <= '0;
425	            burst_offset_ff <= '0;
426	            read_address <= '0;
427	            read_length <= '0;
428	            read_pending <= '0;
429	            timer_ff <= '0;
430	            write_address <= '0;
431	            write_length <= '0;
432	            write_pending <= '0;
433	        end
434	        else
435	        begin
436	            //
437	            // SDRAM control
438	            //
439	            state_ff <= state_nxt;
440	            timer_ff <= timer_nxt;
441	            burst_offset_ff <= burst_offset_nxt;
442	            refresh_timer_ff <= refresh_timer_nxt;
443	            access_is_read_ff <= access_is_read_nxt;
444	            if (state_ff == STATE_OPEN_ROW)
445	            begin
446	                if (access_is_read_ff)
447	                begin
448	                    active_row[read_bank] <= read_row;
449	                    bank_active[read_bank] <= 1;
450	                end
451	                else
452	                begin
453	                    active_row[write_bank] <= write_row;
454	                    bank_active[write_bank] <= 1;
455	                end
456	            end
457	            else if (state_ff == STATE_AUTO_REFRESH0)
458	            begin
459	                // The precharge all command will close all active banks
460	                for (int i = 0; i < NUM_BANKS; i++)
461	                    bank_active[i] <= 0;
462	            end
463	
464	            //
465	            // AXI Bus Interface
466	            //
467	            if (write_pending && state_ff == STATE_WRITE_BURST &&
468	                state_nxt != STATE_WRITE_BURST)
469	            begin
470	                // The bus transfer may be longer than the SDRAM burst.
471	                // Determine if we are done yet.
472	                write_length <= write_length - 8'(SDRAM_BURST_LENGTH);
473	                write_address <= write_address + INTERNAL_ADDR_WIDTH'(SDRAM_BURST_LENGTH);
474	                if (write_length == SDRAM_BURST_LENGTH - 1)
475	                    write_pending <= 0;
476	            end
477	            else if (axi_bus.m_awvalid && !write_pending)
478	            begin
479	                // Start a write burst
480	
481	                // Ensure the the burst is aligned on an SDRAM burst boundary.
482	                assert(((axi_bus.m_awlen + 1) & (SDRAM_BURST_LENGTH - 1)) == 0);
483	                assert((axi_bus.m_awaddr & (SDRAM_BURST_LENGTH - 1)) == 0);
484	
485	`ifdef SIMULATION
486	                // Make sure memory address is in memory range
487	                if (axi_bus.m_awaddr >= MEMORY_SIZE)
488	                begin
489	                    $display("sdram: write address out of range %x", axi_bus.m_awaddr);
490	                    $finish;
491	                end
492	`endif
493	
494	                // axi_bus.m_awaddr is in terms of bytes.  Convert to # of transfers.
495	                write_address <= INTERNAL_ADDR_WIDTH'(axi_bus.m_awaddr[AXI_ADDR_WIDTH - 1:$clog2(DATA_WIDTH / 8)]);
496	                write_length <= axi_bus.m_awlen;
497	                write_pending <= 1'b1;
498	            end
499	
500	            if (read_pending && state_ff == STATE_READ_BURST &&
501	                state_nxt != STATE_READ_BURST)
502	            begin
503	                read_length <= read_length - 8'(SDRAM_BURST_LENGTH);
504	                read_address <= read_address + INTERNAL_ADDR_WIDTH'(SDRAM_BURST_LENGTH);
505	                if (read_length == SDRAM_BURST_LENGTH - 1)
506	                    read_pending <= 0;
507	            end
508	            else if (axi_bus.m_arvalid && !read_pending)
509	            begin
510	                // Start a read burst
511	
512	                // Ensure the the burst is aligned on an SDRAM burst boundary.
513	                assert(((axi_bus.m_arlen + 1) & (SDRAM_BURST_LENGTH - 1)) == 0);
514	                assert((axi_bus.m_araddr & (SDRAM_BURST_LENGTH - 1)) == 0);
515	
516	`ifdef SIMULATION
517	                // Make sure memory address is in memory range
518	                if (axi_bus.m_araddr >= MEMORY_SIZE)
519	                begin
520	                    $display("sdram: read address out of range %x", axi_bus.m_araddr);
521	                    $finish;
522	                end
523	`endif
524	
525	                // axi_bus.m_araddr is in terms of bytes.  Convert to # of transfers.
526	                read_address <= INTERNAL_ADDR_WIDTH'(axi_bus.m_araddr[AXI_ADDR_WIDTH - 1:$clog2(DATA_WIDTH / 8)]);
527	                read_length <= axi_bus.m_arlen;
528	                read_pending <= 1'b1;
529	            end
530	        end
531	    end
532	endmodule
