17	#include "registers.h"
18	#include "vga.h"
19	
20	#define FB_BASE 0x200000
21	
22	// Microinstruction format:
23	//    op (1)  0: load counter 1: loop
24	//    counter value or branch dest (13)
25	//    vsync (1)
26	//    hsync (1)
27	//    new_frame (1)
28	//    in_visible (1)
29	
30	#define OP_LOAD 0
31	#define OP_LOOP 1
32	#define HCOUNT 0
33	#define VCOUNT 1
34	#define F_VISIBLE 1
35	#define F_NEW_FRAME 2
36	#define F_HSYNC 4
37	#define F_VSYNC 8
38	
39	static int ucode_emit_pc;
40	static int ucode_sync_flags;
41	
42	static void emit_op(int opcode, int counter_index, int value)
43	{
44	    REGISTERS[REG_VGA_MICROCODE] = (opcode << 18) | (counter_index << 17)
45	                                   | (value << 4) | ucode_sync_flags;
46	    ucode_emit_pc++;
47	}
48	
49	static void emit_scanline(int hfp, int hs, int hbp, int hres, int visible)
50	{
51	    // Horizontal Front porch
52	    emit_op(OP_LOAD, HCOUNT, hfp - 1);
53	    emit_op(OP_LOOP, HCOUNT, ucode_emit_pc);
54	
55	    // Horizontal Sync pulse
56	    ucode_sync_flags ^= F_HSYNC;
57	    emit_op(OP_LOAD, HCOUNT, hs - 1);
58	    emit_op(OP_LOOP, HCOUNT, ucode_emit_pc);
59	    ucode_sync_flags ^= F_HSYNC;
60	
61	    // Horizontal Back porch
62	    emit_op(OP_LOAD, HCOUNT, hbp - 1);
63	    emit_op(OP_LOOP, HCOUNT, ucode_emit_pc);
64	
65	    // Scanline
66	    if (visible)
67	        ucode_sync_flags ^= F_VISIBLE;
68	
69	    emit_op(OP_LOAD, HCOUNT, hres - 1);
70	    emit_op(OP_LOOP, HCOUNT, ucode_emit_pc);
71	    if (visible)
72	        ucode_sync_flags ^= F_VISIBLE;
73	}
74	
75	//
76	// Compile microcode to generate synchronization signals for resolution and
77	// load into microsequencer.
78	//
79	// - hpf: horizontal front porch length (pixel clocks)
80	// - hs: horizontal sync pulse length
81	// - hbp: horizontal back porch length
82	// - hpol: polarity of horizontal sync, 1 is high, 0 is low
83	// - hres: horizontal resolution (pixels)
84	// - vfp: vertical front porch length (lines)
85	// - vs: vertical sync pulse length
86	// - vbp: vertical back porch length
87	// - vpol: vertical polarity
88	// - vres: vertical resolution (pixels)
89	//
90	static void compile_microcode(int hfp, int hs, int hbp, int hpol, int hres,
91	                              int vfp, int vs, int vbp, int vpol, int vres)
92	{
93	    int v_loop_top;
94	    ucode_sync_flags = (vpol ? 0 : F_VSYNC) | (hpol ? 0 : F_HSYNC);
95	    ucode_emit_pc = 0;
96	
97	    // Must disable sequencer to load new program into it
98	    REGISTERS[REG_VGA_ENABLE] = 0;
99	
100	    // Vertical front porch
101	    emit_op(OP_LOAD, VCOUNT, vfp);
102	    v_loop_top = ucode_emit_pc;
103	    emit_scanline(hfp, hs, hbp, hres, 0);
104	    emit_op(OP_LOOP, VCOUNT, v_loop_top);
105	
106	    // Vertical sync
107	    ucode_sync_flags ^= F_VSYNC;
108	    emit_op(OP_LOAD, VCOUNT, vs);
109	    v_loop_top = ucode_emit_pc;
110	    emit_scanline(hfp, hs, hbp, hres, 0);
111	    emit_op(OP_LOOP, VCOUNT, v_loop_top);
112	    ucode_sync_flags ^= F_VSYNC;
113	
114	    // Vertical back porch
115	    emit_op(OP_LOAD, VCOUNT, vbp);
116	    v_loop_top = ucode_emit_pc;
117	    emit_scanline(hfp, hs, hbp, hres, 0);
118	    emit_op(OP_LOOP, VCOUNT, v_loop_top);
119	
120	    // Visible area
121	    emit_op(OP_LOAD, VCOUNT, vres);
122	    v_loop_top = ucode_emit_pc;
123	    emit_scanline(hfp, hs, hbp, hres, 1);
124	    emit_op(OP_LOOP, VCOUNT, v_loop_top);
125	    REGISTERS[REG_VGA_MICROCODE] = ucode_sync_flags | F_NEW_FRAME;
126	
127	    REGISTERS[REG_VGA_BASE] = FB_BASE;
128	    REGISTERS[REG_VGA_LENGTH] = hres * vres;
129	    REGISTERS[REG_VGA_ENABLE] = 1;
130	}
131	
132	void *init_vga(enum vga_mode mode)
133	{
134	    switch (mode)
135	    {
136	        case VGA_MODE_640x480:
137	            compile_microcode(16, 96, 48, 0, 640, 10, 2, 33, 0, 480);
138	            break;
139	
140	        case VGA_MODE_640x400:
141	            compile_microcode(16, 96, 48, 0, 640, 12, 2, 35, 1, 400);
142	            break;
143	
144	        default:
145	            return 0;
146	    }
147	
148	    return (void*) FB_BASE;
149	}
