#include "registers.h"

#define UART_TX_READY 	(1 << 0)

void _write_uart(char ch)
{
    while ((REGISTERS[REG_UART_STATUS] & UART_TX_READY) == 0)
        ;	// Wait for space

    REGISTERS[REG_UART_TX] = ch;
}

int write_console(const char *str, int length)
{
    int i;

    for (i = 0; i < length; i++)
        _write_uart(str[i]);

    return 0;
}

